{
  "claims": [
    {
      "claim_text": "Senate Bill 739 would provide unconditional and direct cash assistance of $1,000 a month to approximately 2,500 youth aging out of the Extended Foster Care Program in California."
    },
    {
      "claim_text": "The implementation cost of the pilot program under SB 739 is approximately $30 million per year, totaling $90 million over three years."
    },
    {
      "claim_text": "Direct cash assistance empowers individuals in ways that traditional social safety net programs do not."
    },
    {
      "claim_text": "The Stockton Economic Empowerment Demonstration (SEED) program supported 125 residents in obtaining stable employment and improving their physical and mental health."
    },
    {
      "claim_text": "Participants in the SEED program obtained full-time employment at more than twice the rate of non-participants."
    },
    {
      "claim_text": "Nearly 65% of transition-age youth in foster care reported having lost their jobs, with almost a quarter (23%) at risk of losing their housing."
    },
    {
      "claim_text": "Youth aging out of the foster care system often lack familial support and are at risk of falling into homelessness."
    },
    {
      "claim_text": "Transitional age youth without familial support frequently end up victimized or incarcerated for committing crimes to support themselves."
    },
    {
      "claim_text": "More than financial support, UBI empowers young people to decide how to spend the money to meet their specific needs."
    }
  ]
}
